class Solution {
    public int numberOfSpecialChars(String word) {
        int count = 0;
        for (char c = 'a'; c <= 'z'; c++) {
            int lowerIndex = word.indexOf(c);
            int upperIndex = word.indexOf((char) (c - 32));
            if (lowerIndex != -1 && upperIndex != -1 && lowerIndex < upperIndex) {
                count++;
            }
        }
        return count;
    }
}
